// Універсальний парсер для AI Agent відповідей
function extractText(data) {
  if (typeof data === 'string') {
    try {
      const parsed = JSON.parse(data);
      return extractText(parsed);
    } catch {
      return data;
    }
  }

  if (Array.isArray(data)) {
    return extractText(data[0]);
  }

  if (typeof data === 'object' && data !== null) {
    if (data.content) return data.content;
    if (data.choices && Array.isArray(data.choices) && data.choices[0]) {
      return data.choices[0].message?.content || data.choices[0].content;
    }
    if (data.output) {
      if (typeof data.output === 'string') {
        try {
          const parsed = JSON.parse(data.output);
          return extractText(parsed);
        } catch {
          return data.output;
        }
      }
      return extractText(data.output);
    }
    if (data.response) return extractText(data.response);
    if (data.text) return extractText(data.text);
    if (data.message && data.message.content) return data.message.content;

    for (const key in data) {
      if (key.toLowerCase().includes('content') || 
          key.toLowerCase().includes('text') || 
          key.toLowerCase().includes('response')) {
        const result = extractText(data[key]);
        if (result && typeof result === 'string') {
          return result;
        }
      }
    }
  }

  return String(data);
}

const input = $input.all()[0].json;

try {
  const cleanText = extractText(input);

  const finalText = cleanText
    .replace(/\\"/g, '"')
    .replace(/\\n/g, '\n')
    .replace(/\\t/g, '\t')
    .trim();

  return { 
    json: { 
      output: finalText 
    } 
  };

} catch (error) {
  return { 
    json: { 
      output: JSON.stringify(input),
      error: error.message 
    } 
  };
}
